import {
	makeElement,
	createElHelpers,
	omit,
	overridable,
	toWritableStores,
} from '$lib/internal/helpers/index.js';
import type { Defaults } from '$lib/internal/types.js';
import { writable } from 'svelte/store';
import type { CreateProgressProps } from './types.js';

const defaults = {
	defaultValue: 0,
	max: 100,
} satisfies Defaults<CreateProgressProps>;

const { name } = createElHelpers('progress');

export const createProgress = (props?: CreateProgressProps) => {
	const withDefaults = { ...defaults, ...props } satisfies CreateProgressProps;

	const options = toWritableStores(omit(withDefaults, 'value'));
	const { max } = options;
	const valueWritable = withDefaults.value ?? writable(withDefaults.defaultValue);
	const value = overridable(valueWritable, withDefaults?.onValueChange);

	const root = makeElement(name(), {
		stores: [value, max],
		returned: ([$value, $max]) => {
			return {
				value: $value,
				max: $max,
				role: 'meter',
				'aria-valuemin': 0,
				'aria-valuemax': $max,
				'aria-valuenow': $value,
				'data-value': $value,
				'data-state': $value === null ? 'indeterminate' : $value === $max ? 'complete' : 'loading',
				'data-max': $max,
			} as const;
		},
	});

	return {
		elements: {
			root,
		},
		states: {
			value,
		},
		options,
	};
};

export function createCountdown(initialSeconds = 60) {
  let timeLeft = $state(initialSeconds);
  let isRunning = $state(false);
  let animationId: number | null = null;
  let lastTimestamp: DOMHighResTimeStamp | null = null;

  function tick(timestamp: DOMHighResTimeStamp) {
    if (!lastTimestamp) {
      lastTimestamp = timestamp;
    }

    const elapsed = timestamp - lastTimestamp;

    if (elapsed >= 1000) {
      timeLeft--;
      lastTimestamp = timestamp;

      if (timeLeft <= 0) {
        stop();
        timeLeft = 0;
        return;
      }
    }

    if (isRunning) {
      animationId = requestAnimationFrame(tick);
    }
  }

  function start() {
    if (timeLeft > 0 && !isRunning) {
      isRunning = true;
      lastTimestamp = null;
      animationId = requestAnimationFrame(tick);
    }
  }

  function stop() {
    isRunning = false;
    lastTimestamp = null;
    if (animationId) {
      cancelAnimationFrame(animationId);
      animationId = null;
    }
  }

  function reset(seconds: number) {
    stop();
    timeLeft = seconds;
  }

  function destroy() {
    if (animationId) {
      cancelAnimationFrame(animationId);
    }
  }

  // ensures cleanup happens automatically when the component using createCountdown unmounts
  $effect(() => {
    return () => destroy();
  });

  return {
    get timeLeft() {
      return timeLeft;
    },
    get isRunning() {
      return isRunning;
    },
    start,
    stop,
    reset,
    destroy
  };
}

import { tick } from 'svelte';
import type { Action } from 'svelte/action';
import { isHTMLElement, noop } from '$lib/internal/helpers/index.js';

export type PortalConfig = string | HTMLElement | undefined;

export const usePortal = ((el, target = 'body') => {
	let targetEl;

	if (!isHTMLElement(target) && typeof target !== 'string') {
		return {
			destroy: noop,
		};
	}

	async function update(newTarget: PortalConfig = 'body') {
		target = newTarget;

		if (typeof target === 'string') {
			targetEl = document.querySelector(target);
			if (targetEl === null) {
				await tick();
				targetEl = document.querySelector(target);
			}
			if (targetEl === null) {
				throw new Error(`No element found matching css selector: "${target}"`);
			}
		} else if (target instanceof HTMLElement) {
			targetEl = target;
		} else {
			throw new TypeError(
				`Unknown portal target type: ${
					target === null ? 'null' : typeof target
				}. Allowed types: string (CSS selector) or HTMLElement.`
			);
		}
		el.dataset.portal = '';
		targetEl.appendChild(el);
		el.hidden = false;
	}

	function destroy() {
		el.remove();
	}

	update(target);
	return {
		update,
		destroy,
	};
}) satisfies Action<HTMLElement, PortalConfig>;

const styling = $derived(
    classes ?? {
      backdrop: backdropClass,
      div: divClass,
      nonactive: nonActiveClass,
      active: activeClass
    }
  );

  const theme = $derived(getTheme("sidebar"));

  const breakpointValues = {
    sm: 640,
    md: 768,
    lg: 1024,
    xl: 1280,
    "2xl": 1536
  };

  let innerWidth: number = $state(-1);
  let isLargeScreen = $derived(disableBreakpoints ? false : alwaysOpen || innerWidth >= breakpointValues[breakpoint]);

  // Create reactive context for activeUrl using getter
  const activeUrlContext = {
    get value() {
      return activeUrl;
    }
  };
  setActiveUrlContext(activeUrlContext);

  $effect(() => {
    if (disableBreakpoints) isOpen = true;
  });
  const { base, active, nonactive, div, backdrop: backdropCls } = $derived(sidebar({ isOpen, breakpoint, position, backdrop, alwaysOpen: alwaysOpen && !disableBreakpoints }));

  const selectedStore = $derived(isSingle ? writable<object | null>(null) : undefined);
  let sidebarCtx: SidebarContextType = {
    get closeSidebar() {
      return closeSidebar;
    },
    get activeClass() {
      return active({ class: clsx(theme?.active, styling.active) });
    },
    get nonActiveClass() {
      return nonactive({ class: clsx(theme?.nonactive, styling.nonactive) });
    },
    get isSingle() {
      return isSingle;
    },
    get selected() {
      return selectedStore;
    }
  };

  let transitionParams = $derived(params ? params : { x: -320, duration: 200, easing: sineIn });

  setSidebarContext(sidebarCtx);

import { attachRef, type ReadableBoxedValues } from "svelte-toolbelt";
import { createBitsAttrs } from "$lib/internal/attrs.js";
import type { RefAttachment, WithRefOpts } from "$lib/internal/types.js";

const progressAttrs = createBitsAttrs({
	component: "progress",
	parts: ["root"],
});

interface ProgressRootStateOpts
	extends WithRefOpts,
		ReadableBoxedValues<{
			value: number | null;
			max: number;
			min: number;
		}> {}

export class ProgressRootState {
	static create(opts: ProgressRootStateOpts) {
		return new ProgressRootState(opts);
	}

	readonly opts: ProgressRootStateOpts;
	readonly attachment: RefAttachment;

	constructor(opts: ProgressRootStateOpts) {
		this.opts = opts;
		this.attachment = attachRef(this.opts.ref);
	}

	readonly props = $derived.by(
		() =>
			({
				role: "progressbar",
				value: this.opts.value.current,
				"aria-valuemin": this.opts.min.current,
				"aria-valuemax": this.opts.max.current,
				"aria-valuenow":
					this.opts.value.current === null ? undefined : this.opts.value.current,
				"data-value":
					this.opts.value.current === null ? undefined : this.opts.value.current,
				"data-state": getProgressDataState(this.opts.value.current, this.opts.max.current),
				"data-max": this.opts.max.current,
				"data-min": this.opts.min.current,
				"data-indeterminate": this.opts.value.current === null ? "" : undefined,
				[progressAttrs.root]: "",
				...this.attachment,
			}) as const
	);
}

function getProgressDataState(
	value: number | null,
	max: number
): "indeterminate" | "loaded" | "loading" {
	if (value === null) return "indeterminate";
	return value === max ? "loaded" : "loading";
}

import { isElement, noop } from '$lib/internal/helpers/index.js';
import type { InteractOutsideEvent } from '../interact-outside/types.js';
import { useInteractOutside } from '../index.js';
import type { ModalConfig } from './types.js';
import type { Action } from 'svelte/action';

export const useModal = ((node, config) => {
	let unsubInteractOutside = noop;

	function update(config: ModalConfig) {
		unsubInteractOutside();
		const { onClose, shouldCloseOnInteractOutside, closeOnInteractOutside } = config;

		function closeModal() {
			onClose?.();
		}
		function onInteractOutsideStart(e: InteractOutsideEvent) {
			const target = e.target;
			if (!isElement(target)) return;
			e.stopImmediatePropagation();
		}
		function onInteractOutside(e: InteractOutsideEvent) {
			if (!shouldCloseOnInteractOutside?.(e)) return;
			e.stopImmediatePropagation();
			closeModal();
		}
		unsubInteractOutside = useInteractOutside(node, {
			onInteractOutsideStart,
			onInteractOutside: closeOnInteractOutside ? onInteractOutside : undefined,
			enabled: closeOnInteractOutside,
		}).destroy;
	}

	update(config);

	return {
		update,
		destroy() {
			unsubInteractOutside();
		},
	};
}) satisfies Action<HTMLElement, ModalConfig>;

