import { writable } from 'svelte/store';

export function debounceable<T>(initialValue: T, wait = 0) {
	const store = writable({ value: initialValue, debounced: initialValue });
	let timeout: NodeJS.Timeout | undefined;

	function debouncedSet(value: T) {
		store.update((state) => {
			state.value = value;
			return state;
		});

		if (timeout) {
			clearTimeout(timeout);
		}

		timeout = setTimeout(() => {
			store.update((state) => {
				state.debounced = state.value;
				return state;
			});
		}, wait);
	}

	function debouncedUpdate(fn: (value: T) => T) {
		store.update((state) => {
			state.value = fn(state.value);
			return state;
		});

		if (timeout) {
			clearTimeout(timeout);
		}

		timeout = setTimeout(() => {
			store.update((state) => {
				state.debounced = state.value;
				return state;
			});
		}, wait);
	}

	function set(value: T) {
		store.update((state) => {
			state.value = value;
			state.debounced = value;
			return state;
		});
	}

	function update(fn: (value: T) => T) {
		store.update((state) => {
			state.value = fn(state.value);
			state.debounced = state.value;
			return state;
		});
	}

	return {
		...store,
		debouncedSet,
		debouncedUpdate,
		set,
		update,
	};
}

import {
	components,
	darkMode,
	gettingStarted,
	installation,
	migration,
	registry,
} from "$content/index.js";
import { error } from "@sveltejs/kit";
import type { Component } from "svelte";

const allDocs = [
	...gettingStarted,
	...migration,
	...components,
	...installation,
	...darkMode,
	...registry,
];

type DocResolver = () => Promise<{ default: Component; metadata: components }>;
type DocMetadata = (typeof allDocs)[number];

function transformPath(path: string): string {
	return path.replace("/content/", "").replace(".md", "").replace("/index", "").trim();
}

function getDocMetadata(slug: string): DocMetadata | undefined {
	return allDocs.find((doc) => doc.path === slug);
}

export async function getDoc(
	_slug: string
): Promise<{ component: Component; metadata: DocMetadata }> {
	const modules = import.meta.glob("/content/**/*.md");
	const slug = _slug === "" ? "index" : _slug;

	let match: { path?: string; resolver?: DocResolver } = {};

	for (const [path, resolver] of Object.entries(modules)) {
		if (transformPath(path) === slug) {
			match = { path, resolver: resolver as unknown as DocResolver };
			break;
		}
	}

	const doc = await match?.resolver?.();
	const metadata = getDocMetadata(slug);

	if (!doc || !metadata) {
		error(404, "Could not find the documentation page.");
	}

	return {
		component: doc.default,
		metadata,
	};
}

